import sysimport datetimeimport jsonfrom neo4j_migration.model_bootstrap import Neo4jContext, DEFAULT_DATABASEfrom neo4j_migration.nodes import StaticList,NodeEncoderclass StaticListRun(Neo4jContext):    def __init__(self, label="StaticList",database=DEFAULT_DATABASE):        super().__init__(label, database)    @classmethod    def single_query(cls, tx):        select_query = """                MATCH (n:StaticList})                WITH DISTINCT n.Status AS Status                RETURN Status                """        result = tx.run(select_query)        nodes = []        nodes = [row["Status"] for row in result]        if len(nodes) > 0:            return nodes        return None    @classmethod    def create_batch(cls, tx, items:list):        raws = json.dumps(items, cls=NodeEncoder)        batch = json.loads(raws)        create_bulk = """            UNWIND $batch as row            MERGE (n:StaticList {ListID:row.ListID,ItemID:row.ItemID})            ON CREATE SET n.ItemNameDisplay=row.ItemNameDisplay, n.Status=row.Status            RETURN ID(n) as NID            """                # node first        r_result = tx.run(create_bulk, batch=batch)        rIDs = [row["NID"] for row in r_result]        return rIDs    @classmethod    def update_batch(cls, tx, items:list):        raws = json.dumps(items, cls=NodeEncoder)        batch = json.loads(raws)        # add relationship        create_bulk = """            UNWIND $batch as row            MERGE (n:StaticList {ListID:row.ListID,ItemID:row.ItemID})            ON MATCH SET n.ItemNameDisplay=row.ItemNameDisplay,n.Status=row.Status            RETURN ID(n) as NID            """        r_result = tx.run(create_bulk, batch=batch)        rIDs = [row["NID"] for row in r_result]        return rIDs    @classmethod    def delete_batch(cls, tx, items:list):        raws = json.dumps(items, cls=NodeEncoder)        batch = json.loads(raws)        # remove AIO        remove_all = """            UNWIND $batch as row            MATCH (n:StaticList {ListID:row.ListID,ItemID:row.ItemID})            DETACH DELETE n            """        tx.run(remove_all, batch=batch)    #binlog processing    @classmethod    def create_binlog(cls, tx, raws:list):        batch = [StaticList(r["after"]["ListID"],r["after"]["ItemID"],r["after"]["ItemNameDisplay"],r["after"]["Status"]) for r in raws]        cls.create_batch(tx, batch)    @classmethod    def update_binlog(cls, tx, raws:list):        batch = [StaticList(r["after"]["ListID"],r["after"]["ItemID"],r["after"]["ItemNameDisplay"],r["after"]["Status"]) for r in raws]        cls.update_batch(tx, batch)    @classmethod    def delete_binlog(cls, tx, raws:list):        batch = [StaticList(r["before"]["ListID"],r["before"]["ItemID"]) for r in raws]        cls.delete_batch(tx, batch)